namespace SecureLoggingExample
{
    public static class SecureOrderFunction
    {
        [FunctionName("SecureProcessOrder")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "post", Route = "orders")] HttpRequest req,
            ILogger log)
        {
            var correlationId = Guid.NewGuid().ToString("N")[..12];

            // SECURE: Log only safe, non-sensitive headers
            log.LogInformation("[{CorrelationId}] Request received: {Method} {Path}",
                correlationId, req.Method, req.Path);
            log.LogInformation("[{CorrelationId}] Content-Type: {ContentType}, Content-Length: {ContentLength}",
                correlationId,
                req.ContentType ?? "not specified",
                req.ContentLength?.ToString() ?? "unknown");

            // SECURE: Log presence of auth header, not its value
            bool hasAuth = req.Headers.ContainsKey("Authorization");
            log.LogInformation("[{CorrelationId}] Authorization header present: {HasAuth}", correlationId, hasAuth);

            string requestBody = await new StreamReader(req.Body).ReadToEndAsync();

            try
            {
                var order = JsonSerializer.Deserialize<OrderRequest>(requestBody);

                if (order == null)
                {
                    log.LogWarning("[{CorrelationId}] Failed to deserialize request body", correlationId);
                    return new BadRequestObjectResult(new { error = "Invalid request body", correlationId });
                }

                // SECURE: Log only non-sensitive, masked, or tokenized identifiers
                string maskedEmail = MaskEmail(order.Email);
                string maskedCard = MaskCreditCard(order.CreditCardNumber);
                log.LogInformation("[{CorrelationId}] Processing order for user: {MaskedEmail}, card: {MaskedCard}, product: {ProductId}, qty: {Quantity}",
                    correlationId, maskedEmail, maskedCard, order.ProductId, order.Quantity);

                // SECURE: Use parameterized queries and don't log parameter values
                string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

                const string query = "INSERT INTO Orders (Email, Name, ProductId, Quantity) VALUES (@Email, @Name, @ProductId, @Quantity)";
                log.LogInformation("[{CorrelationId}] Executing parameterized INSERT into Orders table", correlationId);

                using var connection = new SqlConnection(connectionString);
                await connection.OpenAsync();
                using var command = new SqlCommand(query, connection);
                command.Parameters.AddWithValue("@Email", order.Email);
                command.Parameters.AddWithValue("@Name", order.FullName);
                command.Parameters.AddWithValue("@ProductId", order.ProductId);
                command.Parameters.AddWithValue("@Quantity", order.Quantity);

                int rowsAffected = await command.ExecuteNonQueryAsync();
                log.LogInformation("[{CorrelationId}] Insert completed. Rows affected: {RowsAffected}", correlationId, rowsAffected);

                var orderId = Guid.NewGuid();
                log.LogInformation("[{CorrelationId}] Order {OrderId} processed successfully", correlationId, orderId);

                return new OkObjectResult(new { message = "Order processed", orderId, correlationId });
            }
            catch (SqlException ex)
            {
                // SECURE: Log error code and correlation ID, not full SQL or data
                log.LogError("[{CorrelationId}] Database error. SqlError: {ErrorNumber}, State: {State}, Severity: {Severity}",
                    correlationId, ex.Number, ex.State, ex.Class);

                // SECURE: Return generic error to client with correlation ID for support lookup
                return new ObjectResult(new
                {
                    error = "A database error occurred. Please contact support.",
                    correlationId
                })
                { StatusCode = 500 };
            }
            catch (JsonException ex)
            {
                log.LogWarning("[{CorrelationId}] JSON parsing error at path: {Path}",
                    correlationId, ex.Path);

                return new BadRequestObjectResult(new
                {
                    error = "Invalid JSON in request body.",
                    correlationId
                });
            }
            catch (Exception ex)
            {
                // SECURE: Log exception type and message but not request body or headers
                log.LogError(ex, "[{CorrelationId}] Unhandled exception of type {ExceptionType}: {Message}",
                    correlationId, ex.GetType().FullName, ex.Message);

                return new ObjectResult(new
                {
                    error = "An unexpected error occurred. Please contact support.",
                    correlationId
                })
                { StatusCode = 500 };
            }
        }

        private static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email)) return "[empty]";
            var parts = email.Split('@');
            if (parts.Length != 2) return "[invalid-email]";
            var local = parts[0];
            var masked = local.Length <= 2
                ? "***"
                : local[0] + new string('*', local.Length - 2) + local[^1];
            return $"{masked}@{parts[1]}";
        }

        private static string MaskCreditCard(string cardNumber)
        {
            if (string.IsNullOrEmpty(cardNumber)) return "[empty]";
            var digits = new string(cardNumber.Where(char.IsDigit).ToArray());
            if (digits.Length < 4) return "[invalid]";
            return $"****-****-****-{digits[^4..]}";
        }
    }
